use std::borrow::Cow;

fn collect_errors_vec_string(n: u32) -> Vec<String> {
    let mut errors: Vec<String> = vec![];
    for i in 0..n {
        if i % 2 == 0 {
            errors.push("something went wrong".to_string());
        } else {
            errors.push(format!("something went wrong on line {}", i));
