    }
    errors
}

fn collect_errors_vec_cow(n: u32) -> Vec<Cow<'static, str>> {
    let mut errors: Vec<Cow<'static, str>> = vec![];
    for i in 0..n {
        if i % 2 == 0 {
            errors.push(Cow::Borrowed("something went wrong"));
        } else {
            errors.push(Cow::Owned(format!("something went wrong on line {}", i)));
        }
    }
    errors
}
```

